<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Scheduling</h1><p class="text-muted mb-0">Jobs scheduled from <?=e($start)?> through <?=e($end)?>.</p></div></div><form method="get" class="card card-body mb-4"><div class="row g-2 align-items-end"><div class="col-md-4"><label class="form-label">Start</label><input type="date" name="start" value="<?=e($start)?>" class="form-control"></div><div class="col-md-4"><label class="form-label">End</label><input type="date" name="end" value="<?=e($end)?>" class="form-control"></div><div class="col-md-4"><button class="btn btn-primary">Apply</button></div></div></form><div class="card"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Date</th><th>Time</th><th>Customer</th><th>Service</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($jobs as $j):?><tr><td><?=e(date('M j, Y',strtotime($j['scheduled_start'])))?></td><td><?=e(date('g:i A',strtotime($j['scheduled_start'])))?></td><td><?=e($j['display_name'])?></td><td><?=e($j['service_summary'])?></td><td><?=e($j['status'])?></td><td class="text-end"><a href="/portal/jobs/<?=$j['id']?>" class="btn btn-sm btn-outline-primary">Open</a></td></tr><?php endforeach; if(!$jobs):?><tr><td colspan="6" class="text-center py-5 text-muted">No jobs in this date range.</td></tr><?php endif?></tbody></table></div></div>
